//latitude.to/articles-by-country/bh/bahrain/12305/naval-support-activity-bahrain"}, {"name": "Camp Arifjan", "lat": 28.878, "lon": 48.1579, "country": "Kuwait", "type": "Army Logistics / Multi-Service Base", "icao": "N/A (Patton Army Heliport OK2A)", "significance": "Primary US Army forward logistics base in theater; ~9,000 personnel; supports aviation maintenance and heavy equipment staging", "assets": ["1st Theater Sustainment Command", "369th Sustainment Brigade", "Patton Army Heliport", "AH-64 Apache (rotational)", "C-130 tactical airlift (transient)", "Navy Expeditionary Logistics Support Group"], "source": "https://en.wikipedia.org/wiki/Camp_Arifjan"}, {"name": "Ali Al Salem Air Base", "lat": 29.3446, "lon": 47.5112, "country": "Kuwait", "type": "Air Base", "icao": "OKAS", "significance": "386th Air Expeditionary Wing; USAF/USMC rotational presence; forward staging for CAS and airlift", "assets": ["386th Air Expeditionary Wing", "F-16C/D Fighting Falcon (rotational)", "A-10C Thunderbolt II (rotational)", "C-130J Hercules", "MQ-9 Reaper (rotational)"], "source": "https://latitude.to/articles-by-country/kw/kuwait/11996/ali-al-salem-air-base"}, {"name": "Prince Sultan Air Base (PSAB)", "lat": 24.0627, "lon": 47.5805, "country": "Saudi Arabia", "type": "Air Base", "icao": "OEPS", "significance": "378th Air Expeditionary Wing; strategic depth base reactivated 2019; Patriot batteries; drone attack intercepted 2 Mar 2026. Major hub in Feb 2026 buildup.", "assets": ["378th Air Expeditionary Wing", "F-15E Strike Eagles (deployed Feb 2026)", "F-35A (deployed Feb 2026)", "F-16C/D Fighting Falcons", "E-3 Sentry AWACS", "KC-135 / KC-46 tankers", "Patriot PAC-3 batteries", "THAAD battery (deployed)"], "source": "https://en.wikipedia.org/wiki/Prince_Sultan_Air_Base"}, {"name": "Naval Support Facility Diego Garcia", "lat": -7.3131, "lon": 72.4236, "country": "British Indian Ocean Territory (BIOT)", "type": "Naval / Air Base — Strategic Bomber Hub", "icao": "FJDG", "significance": "Critical deep-strike hub ~4,300 km from Iran; hosts B-2 Spirit bombers for long-range strike (used in Operation Midnight Hammer, June 2025); nuclear-capable pre-positioned stores; SSN/SSBN transits. Increased transport activity detected Feb 2026 suggesting B-2 pre-positioning.", "assets": ["B-2 Spirit bombers (episodic deployment)", "B-52H Stratofortress (rotational)", "P-8 Poseidon", "KC-135 tankers (transient)", "SSN submarines (transiting, not confirmed on-station)", "Prepositioned War Reserve Materiel", "MPS ships (Maritime Prepositioning Squadron)"], "source": "https://installations.militaryonesource.mil/in-depth-overview/navy-support-facility-diego-garcia"}], "naval": {"overview": "US 5th Fleet (NAVCENT) AOR: ~2.5M sq mi covering Arabian Gulf, Red Sea, Gulf of Oman, Arabian Sea. Three critical chokepoints: Strait of Hormuz, Suez Canal, Bab al-Mandeb.", "carrier_strike_groups": [{"name": "USS Abraham Lincoln (CVN-72) Carrier Strike Group", "cvn": "CVN-72", "air_wing": "Carrier Air Wing 9 (CVW-9)", "status": "Deployed to Indian Ocean / Arabian Sea region from Jan 2026; under CENTCOM control", "embarked_aircraft": ["F/A-18E/F Super Hornet (~44)", "F-35C Lightning II (~10–14)", "EA-18G Growler (electronic warfare, ~5)", "E-2D Advanced Hawkeye (AEW, ~4)", "CMV-22B Osprey (COD)", "MH-60R/S Seahawk (~8)"], "escorts": ["2–3× Arleigh Burke-class DDG (Tomahawk / Aegis BMD)", "1× Ticonderoga-class CG (Aegis)", "1× SSN (undisclosed)"], "source": "https://www.cnn.com/2026/01/26/middleeast/iran-carrier-strike-group-indian-ocean-intl"}, {"name": "USS Gerald R. Ford (CVN-78) Carrier Strike Group", "cvn": "CVN-78", "air_wing": "Carrier Air Wing 8 (CVW-8)", "status": "Ordered to Middle East Feb 2026 from Caribbean/Atlantic; joined theater by late Feb 2026", "embarked_aircraft": ["F/A-18E/F Super Hornet (~44)", "EA-18G Growler (~5)", "E-2D Advanced Hawkeye (~4)", "CMV-22B Osprey", "MH-60R/S Seahawk (~8)"], "escorts": ["2–3× Arleigh Burke-class DDG", "1× Ticonderoga-class CG", "1× SSN (undisclosed)"], "source": "https://www.nbcnews.com/politics/trump-administration/trump-sends-us-aircraft-carrier-ford-middle-east-iran-tensions-high-rcna258903"}], "5th_fleet_assets": ["Task Force 51 – Expeditionary Strike Group (amphibious)", "Task Force 52 – Mine Warfare / Demining Force", "Task Force 53 – Logistics (MSC replenishment ships + C-130, C-40)", "Task Force 56 – Maritime Security / Expeditionary Combat", "Task Force 57 – Maritime Patrol & Reconnaissance (P-8 Poseidon squadrons)", "Task Force 58 – Maritime Surveillance, Northern Persian Gulf", "Task Force 59 – Expeditionary / UxS (unmanned surface / subsurface)", "Multiple Arleigh Burke DDGs (Tomahawk / Aegis BMD-equipped; exact count ~9+ warships in AOR Feb 2026)", "USS Santa Barbara (LCS-32)", "Combined Maritime Forces (47-nation partnership)"], "submarines": "SSN presence in 5th Fleet AOR is standard policy but not disclosed; typically 1–2 submarines in theater at any given time. Virginia-class and Los Angeles-class SSNs carry Tomahawk Block IV/V.", "source": "https://en.wikipedia.org/wiki/United_States_Fifth_Fleet"}, "air_power": {"note": "Figures reflect CENTCOM-deployed force as of late Feb 2026 buildup per OSINT flight-tracking. This is a surge posture above peacetime levels.", "fighters": 228, "fighters_breakdown": {"F/A-18E_F_Super_Hornet": 84, "F_16C_CJ_CM": 54, "F_15E_Strike_Eagle": 36, "F_35A_C_Lightning_II": 42, "EA_18G_Growler_EW": 18, "A_10C_Thunderbolt_II": 12, "note": "Additional ~113 aircraft at European bases (RAF Lakenheath etc.) including 13 F-22, 48 F-35A, 40 F-15E, 12 F-16 available for rapid reinforcement"}, "bombers": 7, "bombers_note": "7 × B-2A Spirit used in Operation Midnight Hammer (June 2025) striking Fordow and Natanz from Diego Garcia. No confirmed B-2 deployments to theater as of late Feb 2026, but increased Diego Garcia activity suggests pre-positioning. B-52H Stratofortress capable of JASSM-ER delivery (20 per aircraft) remains available from CONUS/Diego Garcia.", "tankers": 86, "tankers_note": "~86 KC-46A Pegasus and KC-135R Stratotanker deployed to CENTCOM or en route; total ~127 KC-46/KC-135 mobilized including European-based assets", "isr": 15, "isr_breakdown": {"RC_135V_W_Rivet_Joint": 2, "E_3_Sentry_AWACS": 6, "E_11A_BACN": 5, "P_8_Poseidon": "multiple squadrons (VP-57, rotational)", "RQ_4_Global_Hawk": 2, "MQ_9_Reaper": "multiple (ISR/strike, undisclosed count)"}, "source": "https://www.airandspaceforces.com/us-amasses-more-airpower-middle-east-iran/"}, "missiles": {"tomahawk": {"variants": ["Block IV (land-attack, range ~1,600 km)", "Block V (TLAM-C with JP-10 upgrades)", "Block Va (Maritime Strike Tomahawk MST – anti-ship, EOC Q4 FY2025)", "Block Vb (JMEWS enhanced earth-penetrating warhead)"], "tomahawk_inventory_est": "~3,500–4,500 (all variants, all services)", "inventory_note": "Inventory under stress from Houthi campaign expenditures (>80 Tomahawks fired in single day of Yemen strikes, 2024). Navy bought only 55 Tomahawks in FY2023. Production rate ~5/month (60/year), below minimum sustainment rate of 90/year. $380.8M recertification contract awarded Jan 2026 to extend life of existing inventory through 2029.", "launchers": "140+ US Navy surface warships and submarines capable of firing Tomahawk; Army Typhon MRC (land-based); Marine Corps transitioning to Army", "source": "https://www.aei.org/op-eds/why-is-the-u-s-navy-running-out-of-tomahawk-cruise-missiles/"}, "jassm": {"variants": [{"name": "AGM-158A JASSM", "range_km": 370, "warhead_kg": 450, "note": "Baseline; production concluded Lot 16 (2021)"}, {"name": "AGM-158B JASSM-ER", "range_km": 925, "warhead_kg": 450, "note": "Extended range; primary active variant; full-rate production"}, {"name": "AGM-158B-2 JASSM-ER", "range_km": 925, "warhead_kg": 450, "note": "Updated electronics, anti-jam GPS; LRIP Lot 19 deliveries from 2024"}, {"name": "AGM-158B-3", "range_km": 925, "warhead_kg": 450, "note": "M-code GPS; in development"}, {"name": "AGM-158C LRASM", "range_km": 925, "warhead_kg": 450, "note": "Anti-ship variant; two-way datalink"}, {"name": "AGM-158D", "range_km": 925, "warhead_kg": 450, "note": "Weapon data link, in-flight retargeting; $208M contract, IOT&E through 2027"}, {"name": "JASSM-XR (Extreme Range)", "range_km": 1700, "warhead_kg": 450, "note": "First revealed 2024; extended airframe/fuel; IOC TBD"}], "jassm_inventory_est": "~2,000–3,000+ (all variants)", "inventory_note": "Lockheed Martin delivered 2,000+ by ~2020; production rate now >500/year. $1.93B contract modification (2025) adding JASSM and LRASM production. Used extensively on B-2 (16 per aircraft), B-52 (20 per aircraft), B-1B (24 per aircraft), F-15E, F-35. Confirmed use in Operation Midnight Hammer (June 2025) against Isfahan via Tomahawk and likely JASSM vs. Fordow/Natanz.", "source": "https://armyrecognition.com/news/aerospace-news/2025/us-air-force-invests-600-million-to-accelerate-the-production-of-key-long-range-precision-strike-missiles"}}, "cyber_capabilities": "USCYBERCOM (dual-hatted with NSA) is a Unified Combatant Command with ~7,000 active-duty personnel organized into 147 Cyber Mission Force teams. Proven offensive cyber capabilities: Operation Olympic Games (Stuxnet against Natanz centrifuges, attributed); ongoing Iran-focused persistent engagement operations. EBC budget authority of $2B+. FY2024 CYBER FLAG exercise incorporated offensive cyberspace operations for first time. NSA/CYBERCOM collaboration via China Outcomes Group and Iran-focused teams. Iran's Natanz SCADA/ICS systems, power grid, banking sector, and military C2 are assessed as priority targets. Cobalt Strike and custom implants have been pre-positioned in Iranian networks per CISA/NSA disclosures. Source: https://www.cybercom.mil/Media/News/Article/3739700/posture-statement-of-general-timothy-d-haugh-2024/", "special_operations": "USSOCOM/JSOC assets active in CENTCOM AOR. SEAL Teams (maritime interdiction, direct action), Delta Force/CAG (hostage rescue, HVT strike), 75th Ranger Regiment (airfield seizure), AFSOC (AC-130W/J, MC-130J, MH-47/60). Joint Special Operations Task Force – Arabian Peninsula (JSOTF-AP) based at NSA Bahrain with elements at multiple classified forward sites. Special Activities Center (CIA Ground Branch) operates in parallel. IRGC QF officers, nuclear scientists, and missile engineers have historically been targeted. 5th SF Group (Airborne) provides Theater Special Operations Command (TSOC) for CENTCOM. Estimated 5,000–8,000 SOCOM personnel in CENTCOM AOR at any time. Source: CENTCOM OSINT reporting."}, "iran_forces": {"bases": [{"name": "Bandar Abbas Naval Base / Shahid Bahonar Naval Base", "lat": 27.1837, "lon": 56.2774, "country": "Iran", "province": "Hormozgan", "type": "Naval Base (IRIN Main HQ)", "significance": "Primary IRIN (Islamic Republic of Iran Navy) base. Homeport for frigates, destroyers, submarines. Main ship repair yard. IRGCN also present. Entrance to Strait of Hormuz ~50 km.", "assets": ["Moudge-class destroyers (Jamaran, Sahand – recommissioned Nov 2025, Damavand)", "Fateh-class submarine", "Ghadir-class midget submarines (several)", "Kilo-class (Tareq-class) submarines", "Moudge-class frigate Teftan (under construction)", "Kurdistan floating base ship (Makran-class)", "Noor / Qader anti-ship missile batteries (coastal)", "Support and logistics vessels"], "source": "https://www.latlong.net/place/bandar-abbas-hormozg-n-iran-25702.html"}, {"name": "Bushehr Naval Base / Bushehr Nuclear Power Plant", "lat": 28.8296, "lon": 50.886, "country": "Iran", "province": "Bushehr", "type": "Naval Base / Nuclear Power Plant", "significance": "IRIN secondary base. Bushehr NPP Unit 1 (1,000 MWe, VVER-1000) operational since 2013; Units 2 & 3 under construction. Russian-operated under safeguards.", "assets": ["IRIN patrol boats and fast attack craft", "Bushehr NPP Unit 1 (operational)", "Bushehr NPP Units 2 & 3 (under construction)"], "source": "https://en.wikipedia.org/wiki/Bushehr_Nuclear_Power_Plant"}, {"name": "Chahbahar / Chabahar Naval Base", "lat": 25.2996, "lon": 60.4294, "country": "Iran", "province": "Sistan and Baluchestan", "type": "Naval Base (Indian Ocean access)", "significance": "Iran's only access to open ocean (Gulf of Oman / Indian Ocean). Used for long-range deployments. Several buildings damaged in US strikes 28 Feb 2026.", "assets": ["Makran-class forward base ship (home port)", "IRIN destroyers and frigates (episodic deployment)", "Ghadir-class midget submarines", "Logistics facilities"], "source": "https://x.com/trbrtc/status/2027864449105690872"}, {"name": "Natanz Nuclear Facility (Shahid Ahmadi Roshan)", "lat": 33.725, "lon": 51.7258, "country": "Iran", "province": "Isfahan", "type": "Nuclear Enrichment Facility", "significance": "Iran's primary uranium enrichment site. Above-ground PFEP (Pilot FEP) and large underground FEP (capacity ~50,000 centrifuges, 40–50m underground). Struck by US/Israel in Operation Midnight Hammer (June 2025); new damage confirmed 1–2 March 2026 by satellite imagery; entrance buildings destroyed making facility inaccessible. Adjacent 'Pickaxe Mountain' (Kuh-e Kolang Gaz La) tunnel site under accelerated construction.", "assets": ["IR-1, IR-2m, IR-4, IR-6 centrifuge cascades", "IR-8 advanced centrifuges (pre-installed pre-strike)", "Underground FEP bunker", "Pilot FEP (above ground, largely destroyed)", "Centrifuge assembly plant (likely damaged)"], "source": "https://en.wikipedia.org/wiki/Natanz_Nuclear_Facility"}, {"name": "Fordow Fuel Enrichment Plant (Shahid Ali Mohammadi)", "lat": 34.8846, "lon": 50.996, "country": "Iran", "province": "Qom", "type": "Nuclear Enrichment Facility (Deep Underground)", "significance": "Second enrichment site, ~80–90m underground. Former IRGC missile base. Struck by US GBU-57 Massive Ordnance Penetrators (MOPs) via B-2 bombers in June 2025. Iran claims operational continuity; underground cascade halls reportedly intact. 60% enriched UF6 production previously confirmed here.", "assets": ["IR-1, IR-6 centrifuge cascades (degraded)", "Underground enrichment bunker (partially operational)", "Adjacent missile silo structures (OSINT-confirmed)", "National Vacuum Technology Center", "National Materials Science Center"], "source": "https://en.wikipedia.org/wiki/Fordow_Uranium_Enrichment_Plant"}, {"name": "Isfahan Nuclear Technology Center (ENTC / UCF)", "lat": 32.574, "lon": 51.8261, "country": "Iran", "province": "Isfahan", "type": "Nuclear Research / Fuel Manufacturing Complex", "significance": "Iran's largest nuclear research center; ~3,000 scientists. Houses multiple reactors, uranium conversion facility, fuel manufacturing, zirconium cladding. UCF converts UF6; tunnel complex under site. Struck with Tomahawk cruise missiles (June 2025 per open sources); damage to centrifuge assembly workshops confirmed.", "assets": ["Uranium Conversion Facility (UCF)", "MNSR 27kW research reactor", "HWZPR, GSCR subcritical assemblies", "Fuel Manufacturing Plant", "Isfahan centrifuge workshop (damaged)"], "source": "https://en.wikipedia.org/wiki/Isfahan_Nuclear_Technology/Research_Center"}, {"name": "Parchin Military Complex", "lat": 35.52, "lon": 51.77, "country": "Iran", "province": "Tehran", "type": "Military R&D / Suspected Nuclear Weapons Site", "significance": "Suspected nuclear weapons-related high-explosive testing (Amad Plan). Contains Golab Dareh, Taleghan 1/2 sites. Struck twice by Israel in 2025. Shahid Boroujerdi underground facility for alleged HEU components.", "assets": ["High explosive test facilities", "Ammunition and rocket production", "Golab Dareh bunker complex (35.4955N 51.7442E)", "Shahid Boroujerdi underground complex"], "source": "https://www.nti.org/education-center/facilities/parchin-military-complex/"}, {"name": "Kharg Island Oil Terminal / IRGCN Base", "lat": 29.2356, "lon": 50.31, "country": "Iran", "province": "Bushehr", "type": "Strategic Oil Export Terminal / IRGCN Base", "significance": "Handles ~90% of Iran's oil exports. IRGCN patrol boats and fast attack craft based here. Missile batteries covering central Persian Gulf. High-value target for adversaries.", "assets": ["IRGCN fast attack craft squadron", "Noor/C-802 coastal defense missiles", "Oil loading terminals", "Air defense batteries"], "source": "https://latitude.to/articles-by-country/ir/iran/24153/kharg-island"}, {"name": "Abu Musa Island", "lat": 25.867, "lon": 55.033, "country": "Iran (disputed with UAE)", "province": "Hormozgan", "type": "Strategic Island / IRGCN Forward Base", "significance": "Controls eastern Persian Gulf approaches to Strait of Hormuz. IRGCN garrison with anti-ship missiles. Sovereignty disputed by UAE. Enables flanking attack on USN CSGs transiting strait.", "assets": ["IRGCN garrison and fast attack craft", "Noor/C-802 anti-ship missile battery", "Surface search radar", "Logistics facilities"], "source": "https://en.wikipedia.org/wiki/Abu_Musa"}, {"name": "Strait of Hormuz Coastal Missile Batteries (Generic)", "lat": 27.1, "lon": 56.9, "country": "Iran", "province": "Hormozgan", "type": "Coastal Defense / Anti-Ship Missile Batteries", "significance": "Distributed along Hormozgan coast, Qeshm Island, Hengam Island, and mainland coast facing the strait. Noor (C-802), Qader, and Khalij Fars batteries; can threaten all shipping through strait. Also include Fateh-110/Zolfaghar SRBM batteries for anti-ship and land-attack roles.", "assets": ["Noor anti-ship cruise missile batteries (truck-mobile)", "Qader long-range anti-ship missile batteries", "Khalij Fars anti-ship ballistic missile launchers", "Hormuz-1/2 ARM/anti-ship missiles", "Radar systems (surface search)"], "source": "https://missilethreat.csis.org/missile/fateh-110/"}], "irgc_navy": {"overview": "Islamic Revolutionary Guard Corps Navy (IRGCN). Primary asymmetric maritime force for Persian Gulf, Strait of Hormuz, and Gulf of Oman. Distinct from regular IRIN. Employs swarm tactics, mine warfare, suicide boats, and anti-ship missiles.", "fast_attack_craft": 500, "fast_attack_craft_note": "Estimated 500+ total IRGCN vessels including 100+ fast attack craft delivered Jan 2024 alone. Key types: Peykaap II (missile boat, 25+), Houdong (10), C-14 (5), Tondar, Ashura-class (Kowsar ASCM), Tareq-class (180km missile-capable). New Soleimani-class missile corvettes (4, ~600t, 28 missiles each) represent major capability upgrade. 4 Soleimani-class (Shahid Soleimani, Shahid Hassan Bagheri, Shahid Sayyad Shirazi commissioned; Shahid Ra'is-Ali Delvari under construction). Shahid Abu Mahdi al-Muhandis (1 commissioned, variant class).", "midget_subs": 23, "midget_subs_note": "Up to 23 Ghadir-class midget submarines (shallow-water, torpedoes and mines); 1 Nahang-class (special forces transport). IRGCN operates these.", "mines": "Classified; Iran possesses extensive mine warfare capability including EM-52 rocket-propelled mines, M-08 and M-1908 contact mines, Manta influence mines. Estimated stockpile: thousands. Could rapidly mine Strait of Hormuz (~38 km wide at narrowest).", "anti_ship_missiles": [{"name": "Noor (C-802 derivative)", "range_km": 170, "warhead_kg": 165, "guidance": "Active radar homing, INS", "speed": "Mach 0.9 (subsonic)", "note": "Sea-skimming (5–7m final approach). Iran reverse-engineered from 60 Chinese C-802s purchased 1995. Now fully indigenous. Deployed on ships, coastal batteries, submarines.", "source": "https://weaponsystems.net/system/1216-C-802"}, {"name": "Qader (long-range anti-ship)", "range_km": 300, "warhead_kg": 155, "guidance": "Active radar + INS", "speed": "Mach 0.85", "note": "Longer-range Noor derivative; can also strike coastal targets"}, {"name": "Nasr-1 (C-704 derivative)", "range_km": 35, "warhead_kg": 130, "guidance": "Active radar", "speed": "Mach 0.85", "note": "Lightweight; deployed on fast attack craft and helicopters"}, {"name": "Khalij Fars (Persian Gulf) / Fateh-110 anti-ship variant", "range_km": 300, "warhead_kg": 650, "guidance": "Electro-optical / IR seeker (anti-ship ballistic)", "speed": "Mach 3 terminal", "note": "Anti-ship ballistic missile. Claimed 8m accuracy vs. moving targets (2013 test). Iran claims 'unsinkable' terminal phase. Operational since 2014.", "source": "https://missilethreat.csis.org/missile/fateh-110/"}, {"name": "Kowsar", "range_km": 180, "warhead_kg": 130, "guidance": "Active radar", "speed": "Mach 0.85", "note": "Ashura-class and Tareq-class fast attack craft-mounted; 3D radar-integrated (can target aircraft)"}], "source": "https://www.businessinsider.com/iran-islamic-revolutionary-guard-corps-irgc-fleet-persian-gulf-2024-7", "epic_fury_status": "DESTROYED — 20+ vessels sunk, entire navy being sunk per CENTCOM", "operational_vessels_remaining": "Residual fast attack craft only"}, "regular_navy": {"overview": "Islamic Republic of Iran Navy (IRIN). Conventional blue-water aspirations. Blue-water exercises with Russia, China, Pakistan. AOR includes Arabian Sea, Red Sea approaches.", "frigates_destroyers": 6, "frigates_destroyers_breakdown": [{"name": "Jamaran (Moudge-class)", "type": "Destroyer/Frigate", "displacement_t": 1500, "note": "Lead ship; operational"}, {"name": "Sahand (Moudge-class)", "type": "Destroyer/Frigate", "displacement_t": 1500, "note": "Recommissioned Nov 2025 after 2024 capsizing; upgraded with Sayyad-3/Navvab SAMs (12 missiles total); Abu Mahdi cruise missile integration planned"}, {"name": "Damavand (Moudge-class)", "type": "Destroyer/Frigate", "displacement_t": 1500, "note": "Operational (Caspian Sea)"}, {"name": "Teftan (Moudge-class)", "type": "Destroyer/Frigate", "displacement_t": 1500, "note": "Under construction"}, {"name": "Alvand (Vosper Mk.5)", "type": "Frigate", "displacement_t": 1100, "note": "UK-built; aging but operational"}, {"name": "Alborz (Vosper Mk.5)", "type": "Frigate", "displacement_t": 1100, "note": "UK-built; aging but operational"}], "corvettes": 3, "corvettes_note": "Bayandor-class (US-built, PF-103 type), 2 units. Various patrol corvettes.", "submarines": [{"name": "Tariq-class (Kilo 877EKM)", "type": "Diesel-Electric SSK", "quantity": 3, "note": "Russian-built; 74m; cruise missile launch, mine-laying capable. Despite age (1990s), still operational for strategic missions."}, {"name": "Fateh-class", "type": "Diesel-Electric SSK", "quantity": 2, "note": "Domestically built; entered service 2019/2021; torpedo + missile launch tubes; primarily coastal waters. Successfully tested cruise missile launch from small submarine Aug 2024."}, {"name": "Ghadir-class", "type": "Midget Submarine (SSW)", "quantity": 23, "note": "Very small; shallow water operations; torpedoes and mines; deployed by both IRIN and IRGCN. Surprise attack role in Strait of Hormuz."}, {"name": "Nahang-class", "type": "Special Mission Submarine", "quantity": 1, "note": "Special forces transport; unique design."}], "source": "https://armyrecognition.com/news/navy-news/2025/iranian-navy-recommissions-moudge-class-frigate-sahand-after-2024-capsizing", "epic_fury_status": "DESTROYED — all major surface combatants sunk, 1 submarine sunk by Mark 48 torpedo"}, "ballistic_missiles": [{"name": "Shahab-3", "class": "MRBM", "fuel": "Liquid", "range_km": 1300, "range_note": "800–1,300 km operational; later variants (Shahab-3B/C/D) may reach 1,800–2,000 km with reduced payload", "payload_kg": 1000, "cep_m": 2500, "inventory_est": 200, "inventory_note": "Mainstay of Iran's MRBM force per 2019 DIA. <50 launchers operationally deployed per 2017 NASIC estimate. Mass-produced; 70 units/year capacity in 2008.", "warhead_types": ["HE unitary", "cluster munitions (1,400 submunitions)", "nuclear-capable"], "source": "https://en.wikipedia.org/wiki/Shahab-3"}, {"name": "Emad", "class": "MRBM", "fuel": "Liquid", "range_km": 1700, "payload_kg": 750, "cep_m": 500, "inventory_est": 50, "inventory_note": "Shahab-3 Ghadr rocket with new maneuverable re-entry vehicle; guided RV provides improved accuracy (500m CEP per CSIS). Operational since 2015.", "warhead_types": ["HE", "nuclear-capable (speculative)"], "source": "https://missilethreat.csis.org/missile/emad/"}, {"name": "Ghadr-1 (Ghadr-110)", "class": "MRBM", "fuel": "Liquid", "range_km": 1950, "range_note": "1,600–1,950 km; Jane's estimates 1,950 km. Practical range ~1,600 km with 750 kg payload.", "payload_kg": 750, "cep_m": 300, "inventory_est": 150, "inventory_note": "Extended-range Shahab-3 derivative with aluminum alloy fuselage to reduce weight; stretched fuel tanks; baby-bottle RV. CEP 300m per CSIS. Operational since 2007.", "warhead_types": ["HE", "nuclear-capable"], "source": "https://missilethreat.csis.org/missile/emad/"}, {"name": "Sejjil-2", "class": "MRBM", "fuel": "Solid (two-stage)", "range_km": 2000, "payload_kg": 700, "cep_m": 300, "inventory_est": 100, "inventory_note": "Strategic advantage: faster launch, no pre-fueling intelligence warning. Resurfaced in January 2021 (Great Prophet 15 drills) with upgraded strap-down guidance. Unique Iranian design (not NK copy). Status classified as 'uncertain' per CSIS but assessed operational.", "warhead_types": ["HE", "nuclear-capable"], "source": "https://missilethreat.csis.org/missile/sejjil/"}, {"name": "Khorramshahr-1/2", "class": "MRBM", "fuel": "Liquid", "range_km": 2000, "range_note": "2,000 km declared; actual range with smaller RV may reach 2,500–3,000 km per IISS", "payload_kg": 1800, "cep_m": 600, "inventory_est": 50, "inventory_note": "NK BM-25/Musudan derivative. Heaviest warhead in arsenal. Multiple-warhead (submunitions) capability. Status: in development/limited operational per CSIS.", "warhead_types": ["HE unitary", "submunitions", "nuclear-capable (payload threshold met)"], "source": "https://missilethreat.csis.org/missile/khorramshahr/"}, {"name": "Khorramshahr-4 (Kheibar / Kheibar Shekan)", "class": "MRBM", "fuel": "Liquid (hypergolic, pre-storable)", "range_km": 2000, "payload_kg": 1500, "cep_m": 30, "inventory_est": 30, "inventory_note": "Unveiled May 2023. Iran's most advanced confirmed missile. CEP ~30m per Iranian claims. Launch prep <15 min. Composite airframe. Maneuvering RV (disables guidance on re-entry for EW resistance). Able to 'strike 80 targets' with submunitions warhead.", "warhead_types": ["HE penetrating", "submunitions", "nuclear-capable"], "source": "https://armyrecognition.com/news/army-news/2026/iran-khorramshahr-4-is-the-most-advanced-long-range-missile-able-to-counter-modern-air-defenses"}, {"name": "Fateh-110 (series)", "class": "SRBM", "fuel": "Solid", "range_km": 300, "payload_kg": 650, "cep_m": 100, "inventory_est": 500, "inventory_note": "Most numerous SRBM; multiple variants (A/B/C/D); road-mobile; combat-proven vs. ISIS Syria (2017), Kurdish Iraq (2022), Israel (2025). Variants include anti-ship Khalij Fars and Fateh Mobin (EO seeker). Supplied to Hezbollah and Russia (Ukraine war).", "warhead_types": ["HE unitary", "cluster"], "source": "https://en.wikipedia.org/wiki/Fateh-110"}, {"name": "Zolfaghar", "class": "SRBM", "fuel": "Solid (composite body)", "range_km": 700, "payload_kg": 579, "cep_m": 200, "inventory_est": 200, "inventory_note": "Fateh-110 family; composite body for weight reduction; true ballistic trajectory; GNSS-aided accuracy. Combat use in Syria (2017 ISIS strike). Jane's assesses poor reliability.", "warhead_types": ["HE", "submunitions"], "source": "https://en.wikipedia.org/wiki/Fateh-110"}, {"name": "Dezful", "class": "SRBM/MRBM threshold", "fuel": "Solid", "range_km": 1000, "payload_kg": "Unknown (longer warhead than Zolfaghar)", "cep_m": 150, "inventory_est": 50, "inventory_note": "Tested 2019 in Great Prophet 15 drills. Bridges SRBM/MRBM gap. Range positions it as longer-range Fateh family member.", "warhead_types": ["HE"], "source": "https://www.army-technology.com/features/irans-fateh-ballistic-missile-programmes/"}, {"name": "Shahid Haj Qasem (Haj Qassem)", "class": "MRBM (Fateh family)", "fuel": "Solid", "range_km": 1400, "payload_kg": "Unknown", "cep_m": 30, "inventory_est": 30, "inventory_note": "First MRBM from Fateh family; introduced 2020; maneuvering separating warhead; claimed high accuracy.", "warhead_types": ["HE"], "source": "https://www.army-technology.com/features/irans-fateh-ballistic-missile-programmes/"}, {"name": "Kheibar Shekan (Khorramshahr-4 variant)", "class": "MRBM", "fuel": "Solid", "range_km": 1450, "payload_kg": "Heavy", "cep_m": 30, "inventory_est": 25, "inventory_note": "Solid-fuel MRBM revealed 2022; faster launch prep than liquid systems; used against Israel in 2025 conflict. Range sufficient to strike all US Gulf bases.", "warhead_types": ["HE"], "source": "https://www.army-technology.com/features/irans-fateh-ballistic-missile-programmes/"}], "ballistic_missile_inventory_total": {"pre_june_2025_estimate": "~3,000 total ballistic missiles (IDF/IISS)", "post_june_2025_estimate": "~2,500 remaining after ~500 launched + Israeli strikes on ~200 launchers and manufacturing", "march_2026_pre_war": "~2,500 (IDF assessment Mar 1, 2026; production rate ~100/month post-June 2025 conflict)", "epic_fury_launched": "~806 BMs + ~25 CMs (Days 1-11)", "epic_fury_destroyed_in_strikes": "Unknown additional stockpile destroyed in production/storage site strikes", "launchers_destroyed": "~340 of ~450 TELs (IDF est. ~300 by Mar 7, continuing)", "launchers_remaining": "80-110", "stockpile_remaining": "800-1000 (NDTV/IDF est. ~1000 on Mar 7, declining)", "production_capability": "Severely degraded — Parchin, Shahroud, Esfahan complexes struck", "estimated_remaining": "800-1000"}, "cruise_missiles": [{"name": "Soumar", "range_km": 2500, "range_note": "Iran claims 3,000 km; analysts estimate 2,000–2,500 km (without conformal tanks)", "type": "Ground-launched cruise missile (GLCM)", "guidance": "INS + terrain-following", "warhead": "Conventional; possibly nuclear-capable (derived from Kh-55)", "propulsion": "Turbofan (Soumar); solid rocket booster for launch", "note": "Derived from 12 Ukrainian Kh-55s acquired 2001 via black market. Revealed March 2015.", "source": "https://missilethreat.csis.org/missile/soumar/"}, {"name": "Hoveyzeh", "range_km": 1350, "type": "Ground-launched cruise missile", "guidance": "INS + terrain-following", "warhead": "Conventional", "propulsion": "Turbojet", "note": "Evolution of Soumar; tested to 1,200 km; revealed Feb 2019; used against Israel in April 2024 strike.", "source": "https://missilethreat.csis.org/missile/soumar/"}, {"name": "Paveh", "range_km": 1650, "type": "Ground-launched cruise missile", "guidance": "INS + satellite", "warhead_kg": 175, "propulsion": "Turbojet", "note": "Unveiled 2023; claimed 1,600 km range with 150–200 kg warhead. Iran describes as most advanced cruise missile.", "source": "https://gulfnews.com/world/mena/inside-irans-missile-playbook-arsenal-range-and-strategy-1.500461891"}, {"name": "Abu Mahdi", "range_km": 1000, "type": "Naval cruise missile (truck-launched ground version also)", "guidance": "INS + satellite", "warhead": "Conventional", "propulsion": "Turbojet", "note": "Revealed Aug 2020; naval variant of Hoveyzeh family; blue paint scheme. Named after IRGC-affiliated militia leader.", "source": "https://missilethreat.csis.org/missile/soumar/"}, {"name": "Quds-1 (Cruise missile family)", "range_km": 900, "type": "Ground-launched cruise missile (supplied to Houthis)", "guidance": "INS + GPS", "warhead": "Conventional", "propulsion": "Turbojet", "note": "Houthi-operated variant used in Abqaiq-Khurais 2019 Saudi Aramco attack. Iranian-origin design.", "source": "https://gulfnews.com/world/mena/inside-irans-missile-playbook-arsenal-range-and-strategy-1.500461891"}, {"name": "Ya Ali", "range_km": 700, "type": "Air-launched cruise missile (F-4 Phantom compatible)", "guidance": "INS + GPS + radar terminal", "warhead": "Conventional", "propulsion": "Turbojet", "note": "Air force cruise missile carried by F-4 and potentially Su-22. Precision-guided."}], "air_defense": [{"system": "Bavar-373 (upgraded 2024 variant)", "range_km": 300, "altitude_km": 32, "missile": "Sayyad-4B", "quantity": 6, "quantity_note": "At least 2 batteries confirmed; 2024 upgraded variant with autonomous TELARs. Iran claims superiority over S-300; independent analysts skeptical. Multiple batteries reportedly re-deployed post-June 2025 strikes.", "note": "Iran's premier indigenous long-range SAM. Modular; 6 mobile launchers per battery × 4 missiles each. Detection range 260+ km. Sayyad-4B adds 300 km engagement range vs. Sayyad-4 at 200 km.", "source": "https://militarywatchmagazine.com/article/iran-next-generation-bavar-373-threat"}, {"system": "S-300PMU-2 (Favorit)", "range_km": 200, "altitude_km": 27, "missile": "48N6E2", "quantity": 4, "quantity_note": "4 batteries delivered by Russia from 2017. Primarily protecting Tehran and nuclear sites. Visible redeployments around Tehran, Isfahan, Kharizak (S of Tehran) confirmed by satellite Feb 2026.", "note": "Russian-supplied; multi-target tracking; mobile 5P85 launchers. Can engage cruise missiles and fighters.", "source": "https://www.defensemagazine.com/article/iran-fortifies-tehran-skies-s-300-bavar-373-and-cobra-v8-form-new-anti-access-shield-amid-us-buildup"}, {"system": "Khordad-15 (3rd Khordad)", "range_km": 150, "altitude_km": 27, "missile": "Sayyad-3", "quantity": 6, "quantity_note": "Operational; approximately 4–6 batteries assessed", "note": "Fully mobile; phased-array radar; multi-target (6 simultaneous); shot down US RQ-4 Global Hawk June 2019. Designed to counter stealth and cruise missiles.", "source": "https://en.defence-ua.com/analysis/how_strong_is_iranian_air_defense_network-17663.html"}, {"system": "Talash-3", "range_km": 120, "altitude_km": 22, "missile": "Sayyad-2", "quantity": 8, "quantity_note": "Multiple batteries; medium-range layered defense", "note": "Provides mass and layered depth. Evolved from legacy infrastructure."}, {"system": "Mersad (upgraded Hawk)", "range_km": 45, "altitude_km": 18, "missile": "Shahin", "quantity": 15, "quantity_note": "Widely deployed", "note": "Reverse-engineered and upgraded MIM-23 Hawk. Point defense role."}, {"system": "Arman (anti-ballistic)", "range_km": 120, "altitude_km": 30, "missile": "Sayyad-4 (modified)", "quantity": 2, "quantity_note": "Unveiled 2024; initial deployment scale classified", "note": "Designed for anti-ballistic missile defense; multiple simultaneous engagements claimed."}, {"system": "Rezonans-NE Radar (Russian-supplied OTH)", "range_km": 1100, "altitude_km": "All-altitude", "quantity": 1, "note": "Over-the-horizon long-range detection radar; primary early warning; detects stealth aircraft per Iranian claims."}], "air_force": {"total_fighters": 300, "total_fighters_note": "Estimate ~200–300 fixed-wing aircraft; significant portion non-mission-capable due to sanctions preventing spare parts. Iran's air force described as 'flying museum.' No 5th-gen fighters. Russian Su-35 deliveries speculated for 2026.", "types": [{"name": "F-14A Tomcat", "quantity": 25, "note": "Cold-War era; small number reportedly flyable; AIM-54 Phoenix missiles (some operational with Iranian modifications)"}, {"name": "F-4D/E Phantom II", "quantity": 40, "note": "Aging; some modified to carry Ya Ali cruise missile"}, {"name": "F-5E/F Tiger II", "quantity": 60, "note": "Light fighters; air defense and CAS"}, {"name": "MiG-29A/UB Fulcrum", "quantity": 25, "note": "Procured from Russia/Ukraine 1990; some operational"}, {"name": "Su-24MK Fencer", "quantity": 30, "note": "Strike aircraft; aging; strike and deep interdiction"}, {"name": "Su-25K Frogfoot", "quantity": 13, "note": "Close air support; limited fleet"}, {"name": "Su-22 Fitter", "quantity": 45, "note": "Multi-role; aging Soviet-era"}, {"name": "HESA Saeqeh (F-5 derivative)", "quantity": 24, "note": "Domestic F-5 copy; single-engine; limited capability"}, {"name": "HESA Kowsar", "quantity": 12, "note": "Newer domestic light fighter; F-5 derived"}], "readiness_note": "Assessed 30–50% operational readiness for most types due to sanctions and parts shortages. Air force contributes minimally to integrated air defense; ground-based systems are primary.", "source": "https://www.defensemagazine.com/article/iran-fortifies-tehran-skies-s-300-bavar-373-and-cobra-v8-form-new-anti-access-shield-amid-us-buildup", "epic_fury_status": "DESTROYED — confirmed by SecDef Hegseth March 4, 2026", "operational_aircraft_remaining": 0}, "drone_fleet": [{"type": "Shahed-136 (Geran-2 in Russian service)", "category": "Loitering Munition (One-Way Attack)", "range_km": 2000, "range_note": "970–2,500 km depending on warhead/fuel trade; standard configuration ~2,000 km", "payload_kg": 40, "payload_note": "Standard 30–50 kg; 90 kg heavy warhead variant (reduced range ~650 km) reported May 2024", "speed_kmh": 185, "cost_usd": 20000, "note": "Delta-wing kamikaze drone. Subsonic; low radar cross-section. Used en masse (saturation attacks). GPS + INS guidance. Iran's primary cheap mass-strike weapon. Combat-proven vs. Israel (2024 April and Oct; 2025 conflict), Ukraine (1,000s deployed). Estimated production: hundreds/month.", "source": "https://en.wikipedia.org/wiki/HESA_Shahed_136"}, {"type": "Shahed-238", "category": "Loitering Munition (Jet-Powered)", "range_km": 1500, "payload_kg": 50, "speed_kmh": 500, "note": "Jet-engine variant of Shahed-136; harder to intercept at 500 km/h. Smaller production numbers."}, {"type": "Shahed-129", "category": "MALE UCAV / ISR", "range_km": 1800, "payload_kg": 150, "speed_kmh": 175, "endurance_hrs": 24, "note": "Medium-altitude long-endurance; ISR and strike with Sadid-1 precision munitions. Operated by IRGC and Hezbollah.", "source": "https://jinsa.org/wp-content/uploads/2024/02/Iran-Drones-9-14-22.pdf"}, {"type": "Mohajer-6", "category": "MALE ISR/Strike UAV", "range_km": 2000, "payload_kg": 100, "speed_kmh": 200, "endurance_hrs": 12, "note": "Multirole ISTAR UAV; carries 2–4 Qaem/Almas precision munitions. Wingspan 10m. Ground control station range 200–500 km; satellite link extends to 2,000 km radius.", "source": "https://en.wikipedia.org/wiki/Qods_Mohajer-6"}, {"type": "Karrar", "category": "Combat Drone / Target", "range_km": 1000, "payload_kg": 500, "speed_kmh": 900, "note": "Jet-powered combat/target drone. High speed; can carry anti-ship or anti-ground munitions."}, {"type": "Shahed-191 (Saegheh)", "category": "UCAV (Stealth configuration)", "range_km": 450, "payload_kg": 50, "speed_kmh": 300, "note": "Stealthy UCAV design; smaller payload; precision strike role."}, {"type": "Ababil-5", "category": "UCAV / Tactical Strike", "range_km": 480, "payload_kg": 30, "speed_kmh": 200, "note": "Deployed by IRGC and proxies (Houthis, Hezbollah, Iraqi militias). Combat-proven."}, {"type": "Kaman-22", "category": "Combat UCAV (large)", "range_km": 3000, "payload_kg": 300, "speed_kmh": "Unknown", "note": "Long-range UCAV; large payload; limited production status.", "source": "https://jinsa.org/wp-content/uploads/2024/02/Iran-Drones-9-14-22.pdf"}], "nuclear_program": {"status_note": "Multiple nuclear facilities attacked in Operation Midnight Hammer (US + Israel, June 2025) and subsequent strikes (Feb–Mar 2026). Program degraded but not eliminated. Underground enrichment capacity partially intact.", "enrichment_level": "60% U-235 (pre-strike declared stockpile); some cascade capacity remains at Fordow", "enrichment_level_note": "Iran enriched uranium to 60% purity at Natanz and Fordow. 60% has no credible civilian justification. Pre-strike stockpile: ~275 kg of 60% enriched UF6 (IAEA, Feb 2025). Weapons-grade requires 90%.", "centrifuges_pre_strike": "~18,000–22,000 IR-1 equivalent; ~3,000–4,000 advanced centrifuges (IR-2m, IR-4, IR-6, IR-8) installed", "centrifuges_post_strike": "Unknown; Natanz above-ground PFEP destroyed; FEP underground partially intact; Fordow underground cascades possibly operational at reduced capacity", "breakout_time_pre_strike": "1–2 weeks (IAEA/ISIS/ACA assessment late 2024/early 2026) to produce sufficient HEU for one bomb from 60% stockpile", "breakout_time_post_strike": "Analysts estimate several months to approximately 1 year depending on extent of centrifuge destruction and stockpile accessibility; weaponization requires additional 1–2 years", "facilities": {"Natanz": {"lat": 33.725, "lon": 51.7258, "status": "Extensively damaged; entrances destroyed by GBU-57 MOP (US B-2s); inaccessible as of 3 Mar 2026 per IAEA"}, "Fordow": {"lat": 34.8846, "lon": 50.996, "status": "Struck by US GBU-57 MOPs June 2025; Iran claims no irreversible damage; underground cascades possibly operational"}, "Isfahan_UCF": {"lat": 32.574, "lon": 51.8261, "status": "Centrifuge assembly damaged; UCF struck by Tomahawk in June 2025"}, "Bushehr_NPP": {"lat": 28.8296, "lon": 50.886, "status": "Not struck; under IAEA safeguards; Russian-operated fuel cycle"}, "Parchin": {"lat": 35.52, "lon": 51.77, "status": "Struck twice by Israel in 2025; weaponization facilities extent of damage unclear"}}, "weapon_design": "Iran's weaponization research (Amad Plan-derived) assessed to have produced a workable implosion device design. IAEA 'credible information' of nuclear weapons-related activities at multiple sites. Iran denies weapons intent.", "delivery_systems": "Khorramshahr-4 (range/payload meets nuclear delivery threshold); Shahab-3/Ghadr/Sejjil all nuclear-capable per design lineage; Soumar cruise missile (Kh-55 derivative is nuclear-capable in original design).", "source_breakout": "https://www.armscontrol.org/factsheets/status-irans-nuclear-program-1", "source_isis": "https://isis-online.org/isis-reports/iranian-breakout-timelines-under-jcpoa-type-limits", "source_iaea": "https://iranwarupdates.com/articles/uranium-enrichment-levels-breakout-time-explained", "epic_fury_status": "Natanz struck March 2 (first nuclear target since June 2025). 3+ buildings severely damaged per satellite imagery. IDF says 'systematically dismantling' nuclear infrastructure."}, "irgc_ground_forces": {"note": "IRGC Ground Forces not modeled in detail (wargame focus: air/naval/missiles) but: estimated 125,000 IRGC ground troops + 90,000 Basij militia. Possesses Fateh-110 and Zolfaghar SRBM organic to ground forces. Arash suicide drone squadrons attached to IRGC. Underground missile cities in Kermanshah, Semnan, Gulf coast provinces per open sources.", "missile_cities_note": "At least 5 known underground 'missile cities' with storage, transport, and firing systems for ballistic missiles. In 2020 Iran first fired a ballistic missile from underground.", "source": "https://www.investing.com/news/commodities-news/what-are-irans-ballistic-missile-capabilities-4484097"}, "cyber_capabilities": "Iran Cyber Army and IRGC-affiliated groups (APT33/Elfin, APT34/OilRig, Charming Kitten) are sophisticated state actors. Known capabilities: Shamoon wiper malware (Saudi Aramco 2012); Nitro Zeus (pre-planned cyberattack on Iranian infrastructure, US-origin discovery); destructive attacks on Israeli maritime and industrial infrastructure (2020–2022); US dam/bank attacks (2012–2013). Iran assessed to have implants pre-positioned in US and Gulf state critical infrastructure. Significant EW capability (Cobra-V8 electronic warfare system for radar disruption). Defensive cyber limited vs. US/Israel offensive capabilities as demonstrated by Stuxnet and Operation Midnight Hammer coordination.", "proxy_forces": {"note": "Iran's 'Axis of Resistance' substantially weakened post-2025 Israeli operations but retains some capability", "hezbollah": "Degraded by Israeli operations 2024–2025 but retains tens of thousands of rockets and fighters in Lebanon", "houthis": "Yemen-based; significant missile/drone capability for Red Sea interdiction and strikes on Saudi/UAE/Israeli targets; Iran-supplied Shahed-136, Noor, Zolfaghar", "iraqi_militias": "PMF (Popular Mobilization Forces); Kataeb Hezbollah; equipped with Shahed and Arash drones; threatened to open 'all-out' front in support of Iran if attacked (Feb 2026)", "source": "https://www.cnn.com/2026/01/26/middleeast/iran-carrier-strike-group-indian-ocean-intl"}, "air_defense_status": "SEVERELY DEGRADED — air superiority established, B-52s flying freely", "drone_fleet_status": {"total_launched": "~2,233 OWA drones (Days 1-11)", "launch_rate_decline": "83% from Day 1 (Cooper Mar 5). From 550/day to ~60/day.", "launch_sites": "Heavily struck. Dispersed production still active but degraded.", "production": "Still producing but launch sites and storage increasingly destroyed", "shahed_136_cost": "$20,000-50,000 per unit vs $4M per Patriot interceptor", "defender_cost_ratio": "20-28:1 (defender:attacker for drones)"}}, "war_status": {"operation": "Operation Epic Fury", "day": 11, "date": "2026-03-10", "summary": "Day 11: 3,800+ targets struck. Iran navy destroyed (43 vessels sunk). Air force destroyed. IADS neutralized. 90% reduction in BM launches, 83% reduction in drone launches. ~340 of ~450 TELs destroyed. IDF struck oil refineries (Day 8), rocket engine production (Day 11). Mojtaba Khamenei named Supreme Leader (Day 9). Oil surging toward $120/bbl. France deploying 8 frigates + 2 amphibious carriers. IAEA: enriched uranium stockpile intact. US: 7 KIA, 18 WIA. Israel: 11+ killed. Gulf: 94% intercept rate overall.", "us_casualties": {"kia": 7, "kia_note": "6 on Mar 1-2 (Kuwait), 7th died Mar 7 from wounds", "seriously_wounded": 18, "friendly_fire_aircraft_lost": 3}, "iran_casualties": {"military_killed_hengaw": 2100, "military_killed_note": "As of Day 5 only. Likely much higher by Day 11.", "total_killed_red_crescent": 787, "civilian_killed_hrana": 742, "senior_leaders_killed": 49}, "iran_losses": {"ships_destroyed": 43, "ships_note": "Including drone carrier. CENTCOM Mar 7.", "air_force": "Destroyed", "iads": "Neutralized", "bm_launch_reduction_pct": 90, "drone_launch_reduction_pct": 83, "launchers_destroyed": 340, "launchers_remaining_est": "80-110", "targets_struck_cumulative": 3800, "oil_refineries_struck": true, "oil_refineries_note": "Tondgouyan, Shahran (first time Day 8)"}, "israel_casualties": {"killed": 11, "notes": "Civilian + military from Iranian BMs. Cluster munition warheads confirmed."}, "gulf_civilian_casualties": {"uae": {"killed": 4, "injured": 112}, "kuwait": {"injured": 27}, "saudi": {"killed": 2, "injured": 12, "note": "Al-Kharj Mar 8"}, "bahrain": {"injured": 32, "note": "Sitra Mar 9"}, "overall_intercept_rate": 0.94}}};
